import React, { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import {
  Grid,
  Card,
  CardContent,
  Typography,
  TextField,
  Button,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  Box,
  MenuItem,
  IconButton,
  Divider,
  Stack,
  Autocomplete,
  Paper,
  InputAdornment,
} from '@mui/material';
import DeleteIcon from '@mui/icons-material/Delete';
import ShoppingCartIcon from '@mui/icons-material/ShoppingCart';
import SearchIcon from '@mui/icons-material/Search';
import { API_URL } from '../utils/apiUrl';
import { AuthContext } from '../context/AuthContext';

export default function POSTerminal() {
  const { user } = useContext(AuthContext);
  const isSuperAdmin = user?.role?.name === 'SUPERADMIN';

  const [products, setProducts] = useState([]);
  const [filteredProducts, setFilteredProducts] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [customers, setCustomers] = useState([]);
  const [cart, setCart] = useState([]);
  const [selectedCustomer, setSelectedCustomer] = useState(null);
  const [outlets, setOutlets] = useState([]);
  const [selectedOutletId, setSelectedOutletId] = useState(
    user?.outlet_id || ''
  );

  // ১. ডাটা ফেচিং
  const fetchData = async () => {
    if (!selectedOutletId) return;
    try {
      const [pRes, cRes] = await Promise.all([
        axios.get(
          `${API_URL}/api/outlet-products?outlet_id=${selectedOutletId}`
        ),
        axios.get(`${API_URL}/api/customers?outlet_id=${selectedOutletId}`),
      ]);
      setProducts(pRes.data.data || []);
      setFilteredProducts(pRes.data.data || []);
      setCustomers(cRes.data.data || []);
    } catch (error) {
      console.error('Fetch Error:', error);
    }
  };

  useEffect(() => {
    if (isSuperAdmin) {
      axios
        .get(`${API_URL}/api/outlets`)
        .then((res) => setOutlets(res.data.data || []));
    }
  }, [user]);

  useEffect(() => {
    fetchData();
  }, [selectedOutletId]);

  // সার্চ লজিক
  useEffect(() => {
    const results = products.filter((p) =>
      p.product?.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
    setFilteredProducts(results);
  }, [searchTerm, products]);

  // ২. কার্ট লজিক
  const addToCart = (product) => {
    if (product.stock_quantity <= 0) return alert('স্টক নেই!');
    const existing = cart.find((item) => item.id === product.id);
    if (existing) {
      if (existing.qty >= product.stock_quantity)
        return alert('স্টক লিমিট শেষ!');
      setCart(
        cart.map((item) =>
          item.id === product.id ? { ...item, qty: item.qty + 1 } : item
        )
      );
    } else {
      setCart([...cart, { ...product, qty: 1 }]);
    }
  };

  const updateQty = (id, delta) => {
    setCart((prev) =>
      prev.map((item) => {
        if (item.id === id) {
          const newQty = item.qty + delta;
          return newQty >= 1 && newQty <= item.stock_quantity
            ? { ...item, qty: newQty }
            : item;
        }
        return item;
      })
    );
  };

  const removeFromCart = (id) => setCart(cart.filter((item) => item.id !== id));

  const totalAmount = cart.reduce(
    (sum, item) => sum + item.price * item.qty,
    0
  );

  // ৩. চেকআউট লজিক (Fixed)
  const handleCheckout = async () => {
    if (!selectedCustomer) return alert('দয়া করে কাস্টমার সিলেক্ট করুন!');
    if (cart.length === 0) return alert('কার্ট খালি!');
    if (!selectedOutletId) return alert('আউটলেট সিলেক্ট করা নেই!');

    const payload = {
      outlet_id: Number(selectedOutletId),
      user_id: Number(user.id),
      customer_id: Number(selectedCustomer.id),
      total_amount: Number(totalAmount),
      // পুরো কার্ট পাঠানো হচ্ছে
      items: cart.map((item) => ({
        outlet_product_id: Number(item.id),
        qty: Number(item.qty),
        unit_price: Number(item.price),
      })),
    };

    try {
      // ✅ এখানে এপিআই কলটি হবে
      const response = await axios.post(`${API_URL}/api/sales`, payload);
      if (response.data.success) {
        alert('বিক্রি সফল হয়েছে!');
        setCart([]);
        setSelectedCustomer(null);
        fetchData(); // স্টক আপডেট করার জন্য
      }
    } catch (error) {
      console.error('Sale Error:', error.response?.data);
      alert(
        error.response?.data?.message || 'বিক্রি সম্পন্ন করতে সমস্যা হয়েছে।'
      );
    }
  };

  return (
    <Box sx={{ p: 4, backgroundColor: '#f4f6f8', minHeight: '100vh' }}>
      <Stack
        direction="row"
        justifyContent="space-between"
        alignItems="center"
        sx={{ mb: 4 }}
      >
        <Typography variant="h4" fontWeight="800" color="primary">
          🚀 Rigobyte POS
        </Typography>
        {isSuperAdmin && (
          <TextField
            select
            size="small"
            label="Branch"
            value={selectedOutletId}
            onChange={(e) => {
              setSelectedOutletId(e.target.value);
              setCart([]);
            }}
            sx={{ width: 250, bgcolor: 'white' }}
          >
            {outlets.map((o) => (
              <MenuItem key={o.id} value={o.id}>
                {o.name}
              </MenuItem>
            ))}
          </TextField>
        )}
      </Stack>

      <Grid container spacing={3}>
        {/* প্রোডাক্ট সেকশন */}
        <Grid item xs={12} md={7}>
          <Paper sx={{ p: 2, mb: 2, borderRadius: 3 }}>
            <TextField
              fullWidth
              placeholder="পণ্য খুঁজুন..."
              variant="outlined"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <SearchIcon />
                  </InputAdornment>
                ),
              }}
            />
          </Paper>
          <Grid
            container
            spacing={2}
            sx={{ maxHeight: '70vh', overflowY: 'auto', p: 1 }}
          >
            {filteredProducts.map((p) => (
              <Grid item xs={12} sm={4} key={p.id}>
                <Card
                  elevation={0}
                  sx={{
                    borderRadius: 3,
                    border: '1px solid #e0e0e0',
                    transition: '0.3s',
                    '&:hover': {
                      transform: 'translateY(-5px)',
                      boxShadow: 4,
                      borderColor: 'primary.main',
                    },
                  }}
                  onClick={() => addToCart(p)}
                >
                  <CardContent>
                    <Typography variant="subtitle1" fontWeight="700" noWrap>
                      {p.product?.name}
                    </Typography>
                    <Typography variant="body2" color="text.secondary">
                      স্টক: {p.stock_quantity}
                    </Typography>
                    <Typography
                      variant="h6"
                      color="primary"
                      fontWeight="bold"
                      sx={{ mt: 1 }}
                    >
                      ৳{p.price}
                    </Typography>
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        </Grid>

        {/* কার্ট সেকশন */}
        <Grid item xs={12} md={5}>
          <Paper
            sx={{
              p: 0,
              borderRadius: 4,
              height: '82vh',
              display: 'flex',
              flexDirection: 'column',
              overflow: 'hidden',
            }}
          >
            <Box sx={{ p: 2, bgcolor: 'primary.main', color: 'white' }}>
              <Typography variant="h6">বর্তমান অর্ডার</Typography>
            </Box>

            <Box sx={{ p: 2, flexGrow: 1, overflowY: 'auto' }}>
              <Autocomplete
                options={customers}
                getOptionLabel={(o) => `${o.name} (${o.phone})`}
                onChange={(e, v) => setSelectedCustomer(v)}
                renderInput={(p) => (
                  <TextField
                    {...p}
                    label="কাস্টমার সিলেক্ট করুন"
                    fullWidth
                    variant="standard"
                  />
                )}
                sx={{ mb: 3 }}
              />

              <Table size="small">
                <TableBody>
                  {cart.map((item) => (
                    <TableRow key={item.id}>
                      <TableCell sx={{ fontWeight: 'bold' }}>
                        {item.product?.name}
                      </TableCell>
                      <TableCell>
                        <Stack direction="row" alignItems="center" spacing={1}>
                          <IconButton
                            size="small"
                            onClick={() => updateQty(item.id, -1)}
                          >
                            -
                          </IconButton>
                          <Typography>{item.qty}</Typography>
                          <IconButton
                            size="small"
                            onClick={() => updateQty(item.id, 1)}
                          >
                            +
                          </IconButton>
                        </Stack>
                      </TableCell>
                      <TableCell align="right">
                        ৳{item.price * item.qty}
                      </TableCell>
                      <TableCell align="right">
                        <IconButton
                          color="error"
                          onClick={() => removeFromCart(item.id)}
                        >
                          <DeleteIcon fontSize="small" />
                        </IconButton>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </Box>

            <Divider />
            <Box sx={{ p: 3, bgcolor: '#fafafa' }}>
              <Stack direction="row" justifyContent="space-between" mb={2}>
                <Typography variant="h5" fontWeight="bold">
                  মোট:
                </Typography>
                <Typography variant="h5" fontWeight="bold" color="primary">
                  ৳{totalAmount}
                </Typography>
              </Stack>
              <Button
                variant="contained"
                fullWidth
                size="large"
                startIcon={<ShoppingCartIcon />}
                onClick={handleCheckout}
                disabled={cart.length === 0}
                sx={{
                  borderRadius: 3,
                  py: 1.5,
                  fontSize: '1.1rem',
                  textTransform: 'none',
                }}
              >
                অর্ডার সম্পন্ন করুন
              </Button>
            </Box>
          </Paper>
        </Grid>
      </Grid>
    </Box>
  );
}
